Here's a modern MSTest approach using `HttpMessageHandler` mocking, `[Timeout]`, and cancellation tokens:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var handler = new MockHandler("", HttpStatusCode.NotFound);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        var handler = new MockHandler("ok", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_RespectsAlreadyCancelledToken()
    {
        var handler = new MockHandler("ok", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Lightweight test double — no mocking library needed
    private sealed class MockHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public MockHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---------|-----|
| Async tests | `async Task` return type — MSTest awaits them natively |
| Timeouts | `[Timeout(ms)]` fails the test if it hangs (guards against deadlocks) |
| Cancellation | Create a `CancellationTokenSource` with a short timeout, assert `TaskCanceledException` |
| No external mocks | Subclass `HttpMessageHandler` directly — avoids Moq/NSubstitute for `HttpClient` |

The `[Timeout]` attribute is especially important for async tests — without it, a deadlocked test hangs the entire run indefinitely.
